<template><div class="dashboard"><section class="hero lab-hero"><div><span class="eyebrow">LABORATORY OVERVIEW</span><h1>下午好，{{auth.user?.name||'检验师'}}</h1><p>检验队列运行平稳，请优先处理等待时间较长的检查申请。</p><div class="hero-actions"><el-button type="primary" @click="$router.push('/pending')">开始审核结果 <el-icon><Right/></el-icon></el-button><el-button @click="$router.push('/history')">查看报告</el-button></div></div><div class="lab-art"><span></span><span></span><el-icon><DataAnalysis/></el-icon></div></section><section class="stats"><article><span class="stat-icon teal"><el-icon><Document/></el-icon></span><div><p>待审核报告</p><strong>{{stats.pending}}</strong><small>等待结果审核</small></div></article><article><span class="stat-icon blue"><el-icon><CircleCheck/></el-icon></span><div><p>已完成报告</p><strong>{{stats.completed}}</strong><small>累计完成记录</small></div></article><article><span class="stat-icon amber"><el-icon><Timer/></el-icon></span><div><p>最早等待</p><strong>{{oldest}}</strong><small>请优先处理</small></div></article><article><span class="stat-icon violet"><el-icon><Collection/></el-icon></span><div><p>检查项目</p><strong>{{stats.items}}</strong><small>项目字典总数</small></div></article></section><div class="dash-grid"><section class="card queue-card"><div class="card-head"><div><span class="eyebrow">PRIORITY QUEUE</span><h2>待审核队列</h2></div><el-button link type="primary" @click="$router.push('/pending')">查看全部 <el-icon><ArrowRight/></el-icon></el-button></div><div v-loading="loading"><div v-for="(x,index) in pending" :key="x.id" class="lab-queue-item"><span class="queue-no">{{String(index+1).padStart(2,'0')}}</span><div class="patient"><strong>{{x.patientName}}</strong><small>申请号 EX{{String(x.id).padStart(6,'0')}} · {{x.doctorName}}医生</small></div><el-tag :type="x.type==='检验'?'success':'primary'" effect="light" round>{{x.type}}</el-tag><div class="test-name">{{x.itemName}}</div><time>{{waiting(x.createTime)}}</time><el-button type="primary" plain size="small" @click="$router.push('/pending')">审核结果</el-button></div><el-empty v-if="!pending.length&&!loading" description="暂无待审核报告" :image-size="70"/></div></section><section class="card safety-card"><div class="card-head"><div><span class="eyebrow">QUALITY CONTROL</span><h2>报告质量检查</h2></div></div><div class="check-list"><div v-for="(x,i) in checks" :key="x.title"><span>{{i+1}}</span><div><strong>{{x.title}}</strong><p>{{x.desc}}</p></div><el-icon><CircleCheckFilled/></el-icon></div></div><div class="safety-tip"><el-icon><InfoFilled/></el-icon><span>报告提交后将同步至医生端和患者端。</span></div></section></div></div></template>
<script setup lang="ts">import{computed,onMounted,reactive,ref}from'vue';import{Right,DataAnalysis,Document,CircleCheck,Timer,Collection,ArrowRight,CircleCheckFilled,InfoFilled}from'@element-plus/icons-vue';import{getExaminations,getItems}from'@/api/lab';import{useAuthStore}from'@/stores/auth';import type{Examination}from'@/types';const auth=useAuthStore(),loading=ref(false),pending=ref<Examination[]>([]),stats=reactive({pending:0,completed:0,items:0});const checks=[{title:'患者信息',desc:'姓名与申请单一致'},{title:'检查项目',desc:'项目和标本准确无误'},{title:'结果复核',desc:'数据完整、格式规范'},{title:'报告确认',desc:'异常结果重点标注'}];const waiting=(s:string)=>{const m=Math.max(1,Math.floor((Date.now()-new Date(s).getTime())/60000));return m<60?`${m} 分钟`: `${Math.floor(m/60)} 小时`};const oldest=computed(()=>pending.value.length?waiting(pending.value[pending.value.length-1].createTime):'--');onMounted(async()=>{loading.value=true;try{const[p,c,i]=await Promise.all([getExaminations('待检查',1,5),getExaminations('已完成',1,1),getItems()]);pending.value=p.data.data.content;stats.pending=p.data.data.totalElements;stats.completed=c.data.data.totalElements;stats.items=i.data.data.length}finally{loading.value=false}})</script>

